import random

def _power(base, exp, mod):
    res = 1
    base %= mod
    while exp > 0:
        if exp % 2 == 1:
            res = (res * base) % mod
        base = (base * base) % mod
        exp //= 2
    return res

def miller_rabin(n, k=5):
    if n < 2:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0:
        return False

    # Write n-1 as 2^s * d
    s = 0
    d = n - 1
    while d % 2 == 0:
        d //= 2
        s += 1

    for _ in range(k):
        a = random.randint(2, n - 2)
        x = _power(a, d, n)

        if x == 1 or x == n - 1:
            continue

        is_composite_witness = True
        for _ in range(s - 1):
            x = (x * x) % n
            if x == n - 1:
                is_composite_witness = False
                break

        if is_composite_witness:
            return False

    return True
